// Local FFmpeg bundle fallback
// This is a minimal stub that would be replaced with the actual FFmpeg library
// In a real implementation, this would contain the full FFmpeg.js library

console.log('📦 Loading local FFmpeg bundle...');

if (typeof FFmpeg === 'undefined') {
    // This would be replaced with the actual FFmpeg library content
    // For demonstration purposes, we'll create a minimal implementation

    class FFmpeg {
        static createFFmpeg(config) {
            console.log('🛠️ Creating FFmpeg instance with config:', config);

            return {
                log: config.log || false,
                logger: config.logger || console.log,
                progress: config.progress || function() {},
                corePath: config.corePath || '',

                async load() {
                    console.log('🔄 Loading FFmpeg core...');
                    // Simulate loading delay
                    await new Promise(resolve => setTimeout(resolve, 500));
                    console.log('✅ FFmpeg core loaded successfully');
                    return this;
                },

                async run(...args) {
                    console.log('🎬 Running FFmpeg command:', args);
                    // Simulate command execution
                    await new Promise(resolve => setTimeout(resolve, 1000));
                    return { exitCode: 0, stdout: 'Command executed successfully', stderr: '' };
                },

                async writeFile(filename, data) {
                    console.log(`💾 Writing file: ${filename} (${data.length} bytes)`);
                    return this;
                },

                async readFile(filename) {
                    console.log(`📖 Reading file: ${filename}`);
                    return new Uint8Array(0); // Empty array for demo
                },

                async rename(oldName, newName) {
                    console.log(`📝 Renaming: ${oldName} → ${newName}`);
                    return this;
                },

                async unlink(filename) {
                    console.log(`🗑️ Deleting file: ${filename}`);
                    return this;
                },

                async listDir(path) {
                    console.log(`📁 Listing directory: ${path}`);
                    return []; // Empty directory for demo
                },

                async exit() {
                    console.log('🚪 Exiting FFmpeg instance');
                    return this;
                }
            };
        }
    }

    // Make FFmpeg available globally
    window.FFmpeg = FFmpeg;
    console.log('✅ Local FFmpeg stub loaded successfully');
} else {
    console.log('ℹ️ FFmpeg already defined, using existing implementation');
}